# Extract and save captcha images
img_data = data['jcap_check_1']['response']['img']
for key in ['b1', 'b2']:
    if key in img_data and img_data[key].startswith('data:'):
        # Extract base64 data after comma
        b64_data = img_data[key].split(',')[1]
        ext = 'jpg' if 'jpg' in img_data[key] else 'png'
        img_path = os.path.join(OUT_DIR, f'captcha_{key}.{ext}')
        with open(img_path, 'wb') as f:
            f.write(base64.b64decode(b64_data))
        print(f'OK: captcha {key} -> {img_path}')
